import{_ as a,o as d,c as e,a2 as l}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"证券从业资格证考试辅助项目","description":"","frontmatter":{},"headers":[],"relativePath":"projects/knowledge-tools/securities-exam-tool.md","filePath":"projects/knowledge-tools/securities-exam-tool.md"}'),i={name:"projects/knowledge-tools/securities-exam-tool.md"};function r(s,t,n,h,o,p){return d(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="证券从业资格证考试辅助项目" tabindex="-1">证券从业资格证考试辅助项目 <a class="header-anchor" href="#证券从业资格证考试辅助项目" aria-label="Permalink to &quot;证券从业资格证考试辅助项目&quot;">​</a></h1><blockquote><p>证券从业资格证考试辅助项目，是我为自己备考搭建的一套 AI 辅助学习工具。它把网页题库、问卷星押题、Markdown 真题、PDF 讲义和个人复习过程整理成 <span class="text-highlight-blue">可检索、可练习、可统计、可溯源、可复盘</span> 的本地学习系统。</p></blockquote><div class="project-snapshot"><div><strong>4024 题</strong><span>本地题库结构化题目总量</span></div><div><strong>2 个科目</strong><span>金融基础 2162 题，法律法规 1862 题</span></div><div><strong>54 个来源</strong><span>章节练习、真题、押题等来源入口</span></div><div><strong>讲义溯源</strong><span>两科各 600 题与 PDF 讲义考点建立匹配</span></div></div><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>这个项目是一个小型学习数据产品，目标是把刷题、讲义、错题和考点复盘组织起来。</p><p>我在备考证券从业考试时，发现真正的问题是资料过于分散：PDF 讲义、历年真题、押题卷、问卷星网页、Markdown 题目、答案解析和临考复习材料都散在不同地方。资料越多，越难判断应该先复习哪里、错题如何复刷、题目能不能回到讲义原文。</p><p>因此我把问题重新定义为：如何把非结构化备考资料，转成一套可以支持学习决策的数据系统。</p><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>临考前的学习痛点主要有几类：</p><ul><li>题目来源复杂，格式不统一。</li><li>押题、真题、章节练习混在一起，复习路径不清楚。</li><li>答案解析有，但很难回到 PDF 讲义里的原始考点。</li><li>错题和不会题容易遗失，无法形成持续复刷机制。</li><li>章节题量和高频考点不清楚，复习优先级只能靠感觉。</li><li>电脑端和手机端学习难以衔接。</li></ul><p>这和我做数据产品时遇到的问题很像：数据源分散、字段不统一、口径不清晰、结果难以复盘。于是我用数据产品的方法处理备考。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>将讲义、真题、押题和网页题库整理成结构化题库。</li><li>建立题目、章节、题型、来源、答案、解析、讲义页码之间的关系。</li><li>搭建本地 HTML 练习工具，支持刷题、背题、错题和掌握状态记录。</li><li>用章节题量、高频考点和题型分布辅助复习优先级判断。</li><li>临考前生成压缩版模拟卷和冲刺卷，提高最后阶段复习效率。</li></ol><h2 id="我做了什么" tabindex="-1">我做了什么 <a class="header-anchor" href="#我做了什么" aria-label="Permalink to &quot;我做了什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工作方向</th><th>具体工作</th></tr></thead><tbody><tr><td>题库结构化</td><td>将题干、选项、答案、解析、科目、章节、题型、来源等字段拆出来</td></tr><tr><td>来源整合</td><td>整合网页题库、问卷星押题、Markdown 真题和 PDF 讲义</td></tr><tr><td>本地练习页</td><td>构建可在本地打开的 HTML 练习页、背题页和手机端页面</td></tr><tr><td>错题与掌握状态</td><td>支持错题记录、会 / 模糊 / 不会标记和本地缓存</td></tr><tr><td>讲义溯源</td><td>将题目与讲义章节、页码、考点和原文片段建立匹配</td></tr><tr><td>临考压缩</td><td>基于高频章节和题型比例生成 100 题模拟卷、60 题冲刺卷</td></tr><tr><td>复盘输出</td><td>输出项目介绍、面试讲述版、复盘文章和社交媒体短帖版</td></tr></tbody></table><h2 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h2><p>题目被抽象成可分析的数据对象，具备章节、题型、选项、答案和解析等字段。</p><table tabindex="0"><thead><tr><th>字段</th><th>用途</th></tr></thead><tbody><tr><td>科目</td><td>区分金融基础、法律法规</td></tr><tr><td>章节</td><td>支持按知识结构复习</td></tr><tr><td>题型</td><td>区分单选、多选、判断、案例</td></tr><tr><td>题干 / 选项</td><td>形成标准答题对象</td></tr><tr><td>答案 / 解析</td><td>支持即时反馈</td></tr><tr><td>来源</td><td>追踪题目来自章节练习、押题或真题</td></tr><tr><td>掌握状态</td><td>记录会、模糊、不会</td></tr><tr><td>错题状态</td><td>支持错题本和复刷</td></tr><tr><td>讲义页码 / 考点</td><td>回到 PDF 原始知识点</td></tr></tbody></table><p>本地题库当前包含 <span class="text-highlight-blue">4024 道题</span>，其中金融基础 <span class="text-highlight">2162 题</span>，法律法规 <span class="text-highlight">1862 题</span>。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th><th>价值</th></tr></thead><tbody><tr><td>章节筛选</td><td>按科目和章节筛选题目</td><td>回到知识结构复习</td></tr><tr><td>题型筛选</td><td>按单选、多选、判断、案例题筛选</td><td>针对薄弱题型练习</td></tr><tr><td>自动解析</td><td>答题后展示答案和解析</td><td>降低查答案成本</td></tr><tr><td>错题本</td><td>自动记录错题，支持集中复刷</td><td>建立反馈闭环</td></tr><tr><td>掌握状态</td><td>标记会、模糊、不会</td><td>支持临考优先级排序</td></tr><tr><td>讲义出处</td><td>展示讲义页码、章节和考点</td><td>提升答案可信度</td></tr><tr><td>打印汇总</td><td>生成 A4 紧凑版和超紧凑版</td><td>支持离线复习</td></tr><tr><td>手机端页面</td><td>导出移动端本地 HTML</td><td>让碎片时间也能复习</td></tr></tbody></table><h2 id="讲义与题库匹配" tabindex="-1">讲义与题库匹配 <a class="header-anchor" href="#讲义与题库匹配" aria-label="Permalink to &quot;讲义与题库匹配&quot;">​</a></h2><p>我将题目与 PDF 讲义做了匹配，让每道题尽量回到原始知识源。</p><table tabindex="0"><thead><tr><th>科目</th><th style="text-align:right;">讲义切分考点数</th><th style="text-align:right;">匹配题目数</th><th style="text-align:right;">命中讲义考点数</th></tr></thead><tbody><tr><td>金融基础</td><td style="text-align:right;">175</td><td style="text-align:right;">600</td><td style="text-align:right;">154</td></tr><tr><td>法律法规</td><td style="text-align:right;">271</td><td style="text-align:right;">600</td><td style="text-align:right;">212</td></tr></tbody></table><p>这个能力很关键。做错题时，用户不只看到答案，还可以看到题目对应的讲义考点和页码，从而回到知识源头复习。</p><h2 id="临考冲刺" tabindex="-1">临考冲刺 <a class="header-anchor" href="#临考冲刺" aria-label="Permalink to &quot;临考冲刺&quot;">​</a></h2><p>临考前，我基于章节覆盖、高频考点和题型比例生成压缩题集，避免继续盲目刷所有题。</p><p>以法律法规为例，系统生成了：</p><ul><li><span class="text-highlight-blue">100 题模拟卷</span>：按章节覆盖和题型比例组卷，适合计时做题。</li><li><span class="text-highlight-warm">60 题保命卷</span>：偏向高频、多选和易混考点，适合最后背题。</li><li>独立缓存版：100 题和 60 题各自记录会 / 模糊 / 不会，不影响原题库缓存。</li></ul><p>这体现的是数据从“记录”走向“决策”：题库不仅告诉我过去做了什么，也帮助我决定最后阶段应该复习什么。</p><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始资料</span></span>
<span class="line"><span>  -&gt; 题目结构化</span></span>
<span class="line"><span>  -&gt; 章节 / 题型 / 来源打标</span></span>
<span class="line"><span>  -&gt; 讲义页码匹配</span></span>
<span class="line"><span>  -&gt; 做题行为记录</span></span>
<span class="line"><span>  -&gt; 错题与掌握状态</span></span>
<span class="line"><span>  -&gt; 高频题集生成</span></span>
<span class="line"><span>  -&gt; 临考复习决策</span></span></code></pre></div><p>这个项目中的数据驱动，体现在四个层面：</p><ul><li>用章节题量判断复习重点。</li><li>用题型分布安排刷题策略。</li><li>用错题和掌握状态形成反馈闭环。</li><li>用讲义出处提升答案可信度。</li></ul><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>将分散备考资料整理为本地结构化题库。</li><li>搭建本地练习、背题、手机端、打印版等多种学习入口。</li><li>建立题目与讲义之间的溯源关系，提高复习可信度。</li><li>生成临考模拟卷和冲刺卷，帮助有限时间内压缩复习范围。</li><li>完整实践了从资料采集、数据建模、指标设计、产品迭代到决策支持的流程。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目虽然是个人备考场景，但它很完整地体现了我的数据产品思维：把混乱信息整理成结构，把隐性学习过程变成可观察数据，再用工具帮助自己做出更清楚的行动选择。</p>`,38)])])}const b=a(i,[["render",r]]);export{g as __pageData,b as default};
